import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,d as e}from"./app-3c21af73.js";const t={},i=e(`<h1 id="部署fastapi" tabindex="-1"><a class="header-anchor" href="#部署fastapi" aria-hidden="true">#</a> 部署fastapi</h1><h2 id="uvicorn启动fastapi" tabindex="-1"><a class="header-anchor" href="#uvicorn启动fastapi" aria-hidden="true">#</a> uvicorn启动fastapi</h2><p>要在开发环境中启动 FastAPI 应用程序并为其提供静态文件服务，您需要完成以下步骤：</p><ol><li>安装Asgi web 服务器，例如 uvicorn。</li><li>将您的 FastAPI 应用程序作为 ASGI 应用程序运行。</li><li>配置 web 服务器以为您的 FastAPI 应用程序提供静态文件服务。</li></ol><p>下面是一个简单的示例，演示如何使用 uvicorn 部署 FastAPI 应用程序和静态文件：</p><ol><li><p>首先，确保您已经安装了 FastAPI 和 uvicorn：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pip <span class="token function">install</span> fastapi uvicorn
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>在您的 FastAPI 应用程序代码中，将应用程序作为 ASGI 应用程序运行。例如，如果您的 FastAPI 应用程序存储在一个名为 <code>main.py</code> 的文件中，可以使用以下代码：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>pythonCopy codefrom fastapi <span class="token keyword">import</span> FastAPI

app <span class="token operator">=</span> FastAPI<span class="token punctuation">(</span><span class="token punctuation">)</span>

<span class="token decorator annotation punctuation">@app<span class="token punctuation">.</span>get</span><span class="token punctuation">(</span><span class="token string">&quot;/&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">read_root</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span><span class="token string">&quot;Hello&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;World&quot;</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在命令行中，使用以下命令运行应用程序：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>uvicorn main<span class="token punctuation">:</span>app <span class="token operator">-</span><span class="token operator">-</span>workers <span class="token number">4</span> <span class="token operator">-</span><span class="token operator">-</span>host <span class="token number">0.0</span><span class="token number">.0</span><span class="token number">.0</span> <span class="token operator">-</span><span class="token operator">-</span>port <span class="token number">8080</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这将使用 uvicorn 服务器运行 FastAPI 应用程序，监听 0.0.0.0:80 的所有传入请求，并使用 4 个 worker 处理并发请求。</p></li><li><p>如果您的应用程序包含静态文件，例如图像、CSS 或 JavaScript 文件，则可以使用 FastAPI 内置的静态文件处理程序提供这些文件。首先，将这些文件保存在一个名为 <code>static</code> 的目录中，该目录应该位于您的应用程序代码的根目录下。然后，在您的 FastAPI 应用程序代码中，使用以下代码启用静态文件处理程序：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code>pythonCopy codefrom fastapi <span class="token keyword">import</span> FastAPI
<span class="token keyword">from</span> fastapi<span class="token punctuation">.</span>staticfiles <span class="token keyword">import</span> StaticFiles

app <span class="token operator">=</span> FastAPI<span class="token punctuation">(</span><span class="token punctuation">)</span>

app<span class="token punctuation">.</span>mount<span class="token punctuation">(</span><span class="token string">&quot;/static&quot;</span><span class="token punctuation">,</span> StaticFiles<span class="token punctuation">(</span>directory<span class="token operator">=</span><span class="token string">&quot;static&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span> name<span class="token operator">=</span><span class="token string">&quot;static&quot;</span><span class="token punctuation">)</span>

<span class="token decorator annotation punctuation">@app<span class="token punctuation">.</span>get</span><span class="token punctuation">(</span><span class="token string">&quot;/&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">async</span> <span class="token keyword">def</span> <span class="token function">read_root</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
    <span class="token keyword">return</span> <span class="token punctuation">{</span><span class="token string">&quot;Hello&quot;</span><span class="token punctuation">:</span> <span class="token string">&quot;World&quot;</span><span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这个示例中，<code>StaticFiles</code> 中间件被挂载到 <code>/static</code> 路径上，使得以 <code>/static</code> 开头的请求可以被处理为静态文件请求。静态文件的路径将根据 <code>directory</code> 参数指定的目录进行解析。</p></li></ol><h2 id="生产部署" tabindex="-1"><a class="header-anchor" href="#生产部署" aria-hidden="true">#</a> 生产部署</h2><p>FastAPI 是一个基于 ASGI 的现代 Web 框架，它的性能优秀，具有高度的可伸缩性和响应速度快等特点。FastAPI 支持多种 ASGI 服务器和工作进程模型，其中最流行的 ASGI 服务器是 Uvicorn 和 Daphne，而 Gunicorn 则是最流行的 WSGI 服务器之一。下面是关于使用 Uvicorn 和 Gunicorn 的一些考虑因素：</p><ol><li><p>Uvicorn</p><p>Uvicorn 是一个基于 uvloop 和 httptools 的高性能 ASGI 服务器。它被认为是最快的 ASGI 服务器之一，能够处理大量的并发请求。Uvicorn 支持多个工作进程和自动化的重新加载，这使得它在高负载环境下非常可靠。Uvicorn 还可以与 Gunicorn 配合使用，使用 Gunicorn 的 worker 类型来运行 Uvicorn。</p></li><li><p>Gunicorn</p><p>Gunicorn 是一个基于 Python 的 WSGI 服务器，它支持多个工作进程和多个线程，可以轻松处理大量的并发请求。Gunicorn 支持自动化的重新加载和启动失败自动重试，这使得它在生产环境中非常稳定。Gunicorn 也可以与 Uvicorn 配合使用，使用 Uvicorn 的 worker 类型来运行 Gunicorn。</p></li></ol><p>在选择 Uvicorn 或 Gunicorn 时，您需要考虑以下因素：</p><ol><li>性能和可扩展性：如果您需要处理高负载的并发请求，并需要一个高性能的 ASGI 服务器，那么 Uvicorn 可能更适合您。</li><li>生产环境的稳定性：如果您需要一个稳定的服务器来运行您的应用程序，并且能够自动重新加载和启动失败自动重试，那么 Gunicorn 可能更适合您。</li><li>操作和管理：如果您更熟悉 WSGI 服务器，那么 Gunicorn 可能更容易操作和管理。如果您更熟悉 ASGI 服务器，那么 Uvicorn 可能更容易操作和管理。</li></ol><p>总的来说，Uvicorn 是一个快速、可扩展的 ASGI 服务器，适合处理高负载的并发请求，而 Gunicorn 是一个稳定的 WSGI 服务器，适合在生产环境中运行。如果您需要同时使用这两个服务器，那么可以考虑使用 Gunicorn 来管理 Uvicorn。</p><h3 id="启动服务" tabindex="-1"><a class="header-anchor" href="#启动服务" aria-hidden="true">#</a> 启动服务</h3><p>要使用 Gunicorn 来管理 Uvicorn，可以使用 Gunicorn 的 <code>uvicorn</code> worker 类型，它允许您在 Gunicorn 中启动 Uvicorn。以下是使用 Gunicorn 和 Uvicorn 部署 FastAPI 应用的步骤：</p><ol><li><p>安装 Gunicorn 和 Uvicorn：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>pip <span class="token function">install</span> gunicorn uvicorn
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>在命令行中运行以下命令来启动 Uvicorn：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>uvicorn main:app <span class="token parameter variable">--workers</span> <span class="token number">4</span> <span class="token parameter variable">--host</span> <span class="token number">0.0</span>.0.0 <span class="token parameter variable">--port</span> <span class="token number">8000</span> --log-level warning
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>该命令将在端口 8000 上启动 FastAPI 应用，并使用 4 个工作进程处理请求。</p></li><li><p>在命令行中运行以下命令来使用 Gunicorn 启动 Uvicorn：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>gunicorn main:app <span class="token parameter variable">-w</span> <span class="token number">4</span> <span class="token parameter variable">-k</span> uvicorn.workers.UvicornWorker <span class="token parameter variable">-b</span> <span class="token number">0.0</span>.0.0:8000 --log-level warning
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>该命令将使用 Gunicorn 启动 Uvicorn，使用 4 个工作进程处理请求，并在端口 8000 上监听连接。</p></li></ol><h3 id="管理服务" tabindex="-1"><a class="header-anchor" href="#管理服务" aria-hidden="true">#</a> 管理服务</h3><p>如果您需要将应用程序部署到生产环境中，请使用 systemd 或 supervisord 等工具将 Gunicorn 作为服务运行，并将日志记录到日志文件中。</p><h4 id="supervisor" tabindex="-1"><a class="header-anchor" href="#supervisor" aria-hidden="true">#</a> supervisor</h4><p>Supervisor 是一个进程监控工具，可以轻松管理和监控多个进程。在这里，我们将使用 Supervisor 监控上面的 FastAPI 应用程序并将日志记录到文件中。</p><ol><li><p>安装 Supervisor：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">apt-get</span> <span class="token function">install</span> supervisor
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div></li><li><p>编辑 Supervisor 的配置文件：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> <span class="token function">nano</span> /etc/supervisor/conf.d/fastapi.conf
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在此文件中添加以下内容：</p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">program:fastapi</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">command</span><span class="token punctuation">=</span><span class="token value attr-value">/path/to/virtualenv/bin/gunicorn main:app -w 4 -k uvicorn.workers.UvicornWorker -b 0.0.0.0:8000 --log-level warning</span>
<span class="token key attr-name">directory</span><span class="token punctuation">=</span><span class="token value attr-value">/path/to/your/app</span>
<span class="token key attr-name">user</span><span class="token punctuation">=</span><span class="token value attr-value">your_user</span>
<span class="token key attr-name">autostart</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>
<span class="token key attr-name">autorestart</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>
<span class="token key attr-name">stderr_logfile</span><span class="token punctuation">=</span><span class="token value attr-value">/var/log/fastapi.err.log</span>
<span class="token key attr-name">stdout_logfile</span><span class="token punctuation">=</span><span class="token value attr-value">/var/log/fastapi.out.log</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这里，<code>[program:fastapi]</code> 是一个程序的名称，可以随意设置。<code>command</code> 是运行 FastAPI 应用程序的命令，您可以将其替换为您的命令。<code>directory</code> 是应用程序代码所在的目录。<code>user</code> 是应用程序运行的用户。<code>autostart</code> 和 <code>autorestart</code> 用于控制进程的启动和重启。<code>stderr_logfile</code> 和 <code>stdout_logfile</code> 用于将错误日志和标准输出日志记录到文件中。</p></li><li><p>保存并关闭文件。重新加载 Supervisor 配置文件：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> supervisorctl reread
<span class="token function">sudo</span> supervisorctl update
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>这将重新加载配置文件并启动 FastAPI 应用程序。</p></li><li><p>检查 FastAPI 应用程序是否正在运行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">sudo</span> supervisorctl status
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果一切正常，您应该看到类似于以下内容的输出：</p><div class="language-ruby line-numbers-mode" data-ext="rb"><pre class="language-ruby"><code>fastapi <span class="token constant">RUNNING</span> pid <span class="token constant">XXXX</span><span class="token punctuation">,</span> uptime <span class="token constant">XX</span><span class="token symbol">:XX</span><span class="token operator">:</span><span class="token constant">XX</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果出现错误，请检查 <code>stderr_logfile</code> 中的日志文件以获取更多信息。</p></li><li><p>检查日志文件是否正常工作：</p><p>您可以通过查看 <code>/var/log/fastapi.err.log</code> 和 <code>/var/log/fastapi.out.log</code> 中的内容来查看 FastAPI 应用程序的错误日志和标准输出日志。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tail</span> <span class="token parameter variable">-f</span> /var/log/fastapi.err.log
<span class="token function">tail</span> <span class="token parameter variable">-f</span> /var/log/fastapi.out.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><code>tail -f</code> 命令将实时显示日志文件中的内容。</p></li></ol><h4 id="systemd" tabindex="-1"><a class="header-anchor" href="#systemd" aria-hidden="true">#</a> systemd</h4><p>以下是一个示例 systemd 配置文件：</p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Unit</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">Description</span><span class="token punctuation">=</span><span class="token value attr-value">Gunicorn instance to serve myproject</span>
<span class="token key attr-name">After</span><span class="token punctuation">=</span><span class="token value attr-value">network.target</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Service</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">User</span><span class="token punctuation">=</span><span class="token value attr-value">username</span>
<span class="token key attr-name">Group</span><span class="token punctuation">=</span><span class="token value attr-value">www-data</span>
<span class="token key attr-name">WorkingDirectory</span><span class="token punctuation">=</span><span class="token value attr-value">/path/to/myproject</span>
<span class="token key attr-name">Environment</span><span class="token punctuation">=</span><span class="token value attr-value">&quot;<span class="token inner-value">PATH=/path/to/virtualenv/bin</span>&quot;</span>
<span class="token key attr-name">ExecStart</span><span class="token punctuation">=</span><span class="token value attr-value">/path/to/virtualenv/bin/gunicorn main:app -w 4 -k uvicorn.workers.UvicornWorker -b 0.0.0.0:8000 --log-level warning</span>
<span class="token key attr-name">Restart</span><span class="token punctuation">=</span><span class="token value attr-value">always</span>
<span class="token key attr-name">PrivateTmp</span><span class="token punctuation">=</span><span class="token value attr-value">true</span>

<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">Install</span><span class="token punctuation">]</span></span>
<span class="token key attr-name">WantedBy</span><span class="token punctuation">=</span><span class="token value attr-value">multi-user.target</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>您需要将该文件保存为 <code>/etc/systemd/system/myproject.service</code>，并运行以下命令启动服务：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>systemctl daemon-reload
systemctl start myproject
systemctl <span class="token builtin class-name">enable</span> myproject
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>日志可以在 <code>/var/log/syslog</code> 或 <code>/var/log/myproject.log</code> 中找到，具体取决于您的配置。</p><h3 id="nginx反向代理" tabindex="-1"><a class="header-anchor" href="#nginx反向代理" aria-hidden="true">#</a> nginx反向代理</h3><p>最后，您可以使用反向代理工具，例如 Nginx 或 Apache，来将传入的 HTTP 请求路由到您的 FastAPI 应用程序。在 Nginx 中，您可以使用类似于以下的配置文件将请求路由到 FastAPI：</p><div class="language-nginx line-numbers-mode" data-ext="nginx"><pre class="language-nginx"><code><span class="token directive"><span class="token keyword">server</span></span> <span class="token punctuation">{</span>
    <span class="token directive"><span class="token keyword">listen</span> <span class="token number">80</span></span><span class="token punctuation">;</span>
    <span class="token directive"><span class="token keyword">server_name</span> example.com</span><span class="token punctuation">;</span>

    <span class="token directive"><span class="token keyword">location</span> /</span> <span class="token punctuation">{</span>
        <span class="token directive"><span class="token keyword">proxy_pass</span> http://127.0.0.1:8000</span><span class="token punctuation">;</span>
        <span class="token directive"><span class="token keyword">proxy_set_header</span> Host <span class="token variable">$host</span></span><span class="token punctuation">;</span>
        <span class="token directive"><span class="token keyword">proxy_set_header</span> X-Real-IP <span class="token variable">$remote_addr</span></span><span class="token punctuation">;</span>
        <span class="token directive"><span class="token keyword">proxy_set_header</span> X-Forwarded-For <span class="token variable">$proxy_add_x_forwarded_for</span></span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>‍</p>`,30),p=[i];function o(c,l){return a(),s("div",null,p)}const d=n(t,[["render",o],["__file","部署fastapi.html.vue"]]);export{d as default};
